interface MenuButtonProps {
  icon: React.ReactNode;
  label: string;
  emoji: string;
  onClick: () => void;
  className?: string;
}

const MenuButton: React.FC<MenuButtonProps> = ({ icon, label, emoji, onClick, className = "" }) => (
  <button 
    onClick={onClick}
    className={`flex items-center gap-3 p-4 bg-white/60 backdrop-blur-md border border-gray-200 rounded-xl hover:bg-white/80 transition-all active:scale-[0.97] shadow-sm group ${className}`}
  >
    <div className="flex items-center justify-center w-10 h-10 bg-indigo-50 text-indigo-600 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
      {icon}
