    <div className="flex flex-col items-start">
      <div className="flex items-center gap-1.5">
        <span className="text-lg">{emoji}</span>
        <span className="text-[13px] font-bold text-gray-700 uppercase tracking-tight">{label}</span>
      </div>
    </div>
  </button>
);

