import React, { useState, useEffect } from 'react';
import { Send, X, AlertCircle } from 'lucide-react';

interface SubmissionPanelProps {
  action: string | null;
  onClose: () => void;
  onSubmit: (data: { type: string; content: string }) => void;
}

const SubmissionPanel: React.FC<SubmissionPanelProps> = ({ action, onClose, onSubmit }) => {
  const [content, setContent] = useState('');

  // Reset content when action changes
  useEffect(() => {
    setContent('');
  }, [action]);

  if (!action) return null;

  const getPlaceholder = () => {
    switch (action) {
      case 'sell': return 'আপনার জিমেইল লিস্ট এখানে দিন (Email:Password:Recovery)...';
      case 'withdraw': return 'পেমেন্ট মেথড এবং নাম্বার সহ বিস্তারিত লিখুন (৳ পরিমাণ, বিকাশ/নগদ নম্বর)...';
      case 'support': return 'আপনার সমস্যার কথা বিস্তারিত লিখুন...';
      default: return 'এখানে বিস্তারিত লিখুন...';
    }
  };

  const getTitle = () => {
    switch (action) {
      case 'sell': return 'জিমেইল জমা দিন';
      case 'withdraw': return 'উইথড্র রিকোয়েস্ট';
      case 'support': return 'সাপোর্ট মেসেজ';
      default: return 'মেসেজ বক্স';
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!content.trim()) return;
    onSubmit({ type: action, content });
    setContent('');
  };

  return (
    <div className="w-full max-w-4xl mx-auto px-4 mt-6 animate-in slide-in-from-top-4 duration-300">
      <div className="bg-white rounded-3xl shadow-xl border border-gray-200 overflow-hidden">
        <div className="bg-indigo-600 px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2 text-white">
            <AlertCircle className="w-5 h-5" />
            <h3 className="font-black uppercase tracking-tight text-sm">{getTitle()}</h3>
          </div>
          <button 
            onClick={onClose}
            className="p-1 hover:bg-white/20 rounded-full text-white transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6">
          <textarea
            required
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder={getPlaceholder()}
            className="w-full h-48 p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-600 focus:bg-white transition-all text-gray-800 placeholder-gray-400 resize-none font-medium"
          />

          <div className="flex items-center justify-between mt-4">
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">
              Admin will process your request instantly
            </p>
            <button
              type="submit"
              disabled={!content.trim()}
              className="flex items-center gap-2 bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 disabled:opacity-50 transition-all active:scale-95 shadow-lg shadow-indigo-100"
            >
              SEND TO ADMIN
              <Send className="w-4 h-4" />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default SubmissionPanel;

