import React, { useState } from 'react';
import { Copy, Check, X, CheckCircle, User, Mail, Key, ShieldAlert, Info, ArrowRight, Zap, Ban } from 'lucide-react';
import { Task } from '../types.ts';

interface TaskAssignmentProps {
  task: Task;
  onComplete: () => void;
  onCancel: () => void;
}

const TaskAssignment: React.FC<TaskAssignmentProps> = ({ task, onComplete, onCancel }) => {
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showError, setShowError] = useState(false);

  const copyToClipboard = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 2000);
  };

  const handleCompleteClick = () => {
    setIsSubmitting(true);
    // Simulate server-side verification check
    setTimeout(() => {
      setIsSubmitting(false);
      // If it's the first time clicking, show the "Verification Failed" error from the image
      if (!showError) {
        setShowError(true);
      } else {
        // On second try, let it succeed for demo purposes
        onComplete();
      }
    }, 1800);
  };

  if (showError) {
    return (
      <div className="w-full max-w-lg mx-auto px-4 mt-8 animate-in zoom-in-95 duration-300">
        <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden text-left relative">
          {isSubmitting && (
            <div className="absolute inset-0 z-50 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4 rounded-3xl">
              <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
              <p className="font-black text-indigo-600 animate-pulse uppercase tracking-widest text-sm">ভেরিফিকেশন করা হচ্ছে...</p>
            </div>
          )}

          {/* Error Header */}
          <div className="px-6 py-5 flex items-center gap-3">
             <div className="w-8 h-8 flex items-center justify-center">
                <span className="text-red-600 text-3xl">❌</span>
             </div>
             <h2 className="text-2xl font-black text-slate-900 tracking-tight">ভেরিফিকেশন ব্যর্থ!</h2>
          </div>

          <div className="px-8 pb-8 space-y-5">
            <div className="flex items-center gap-2 text-xl font-bold text-gray-800">
              <span className="text-2xl">👇</span> নিচের তথ্য দিয়ে জিমেইল খুলুন:
            </div>

            <div className="space-y-4">
              <div className="flex flex-col gap-1">
                <div className="flex items-center gap-3">
                   <div className="text-slate-400"><User className="w-6 h-6" /></div>
                   <p className="text-lg font-bold text-slate-800">First Name:- <span className="font-mono text-slate-600 font-medium">{task.firstName}</span></p>
                </div>
                <div className="flex items-center gap-3">
                   <div className="text-slate-400"><User className="w-6 h-6" /></div>
                   <p className="text-lg font-bold text-slate-800">Last Name:- <span className="font-mono text-slate-600 font-medium">{task.lastName}</span></p>
                </div>
              </div>

              <div className="flex items-center gap-3">
                 <div className="text-blue-400"><Mail className="w-6 h-6" /></div>
                 <p className="text-lg font-bold text-slate-800">Gmail: <span className="font-mono text-slate-600 font-medium">{task.gmail}</span></p>
              </div>

              <div className="flex items-center gap-3">
                 <div className="text-amber-400"><Key className="w-6 h-6" /></div>
                 <p className="text-lg font-bold text-slate-800">Password: <span className="font-mono text-slate-600 font-medium">{task.password}</span></p>
              </div>

              <div className="flex items-start gap-3">
                 <div className="text-red-400 mt-1"><ShieldAlert className="w-6 h-6" /></div>
                 <p className="text-lg font-bold text-slate-800">Recovery Mail: <span className="font-mono text-slate-600 font-medium break-all">{task.recovery}</span></p>
              </div>
            </div>

            {/* Error Message Box */}
            <div className="flex gap-3 pt-4 border-t border-slate-100">
              <div className="shrink-0 pt-1">
                <span className="text-amber-500 text-2xl">⚠️</span>
              </div>
              <div className="space-y-1">
                <p className="text-lg font-black text-slate-900 leading-tight">সমস্যা: <span className="font-medium text-slate-700">এই নামে কোনো জিমেইল একাউন্ট তৈরি করা হয়নি বা গুগল সার্ভারে পাওয়া যাচ্ছে না।</span></p>
                <p className="text-lg font-medium text-slate-700 leading-tight">অনুগ্রহ করে একাউন্টটি সঠিকভাবে তৈরি করুন এবং আবার চেষ্টা করুন।</p>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="flex flex-col border-t border-slate-200">
             <button 
              onClick={handleCompleteClick}
              disabled={isSubmitting}
              className="flex items-center justify-center gap-3 py-4 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-700 font-black text-xl border-b border-slate-200 transition-all active:bg-emerald-500/30"
            >
              <span className="text-2xl">✅</span> সম্পন্ন হয়েছে
            </button>
            <button 
              onClick={onCancel}
              disabled={isSubmitting}
              className="flex items-center justify-center gap-3 py-4 bg-rose-500/10 hover:bg-rose-500/20 text-rose-700 font-black text-xl transition-all active:bg-rose-500/30"
            >
              <span className="text-2xl">❌</span> বাতিল করুন
            </button>
          </div>
        </div>
        <div className="flex justify-end p-2 px-6">
           <span className="text-xs text-slate-400 font-medium">{new Date().toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
        </div>
      </div>
    );
  }

  const FieldRow = ({ label, value, icon, copyable, fieldId, subLabel }: any) => (
    <div 
      className={`relative group flex flex-col p-4 rounded-xl transition-all ${
        copyable 
        ? 'cursor-pointer hover:bg-slate-50 active:scale-[0.98]' 
        : 'bg-white'
      }`}
      onClick={() => copyable && copyToClipboard(value, fieldId)}
    >
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-2">
          <div className="text-blue-500">
            {icon}
          </div>
          <span className="text-sm font-bold text-gray-800">{label}:</span>
          {copyable && (
            <span className="text-[11px] text-slate-500 font-medium ml-1">
              (কপি করতে ট্যাপ করুন)
            </span>
          )}
        </div>
        {subLabel && (
          <span className="flex items-center gap-1 text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-black uppercase tracking-tighter animate-pulse">
            <Zap className="w-2.5 h-2.5" />
            {subLabel}
          </span>
        )}
      </div>
      <div className="flex items-center gap-2">
        <div className="bg-blue-500 p-1 rounded-sm text-white">
          <ArrowRight className="w-3 h-3" />
        </div>
        <p className="text-lg font-mono font-medium text-slate-700 tracking-tight">:- {value}</p>
        {copiedField === fieldId && (
          <div className="absolute right-4 top-1/2 -translate-y-1/2 bg-green-500 text-white text-[10px] px-2 py-1 rounded font-bold animate-in fade-in zoom-in">
            COPIED!
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="w-full max-w-lg mx-auto px-4 mt-8 animate-in slide-in-from-bottom-8 duration-500">
      <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden text-left relative">
        {isSubmitting && (
          <div className="absolute inset-0 z-50 bg-white/80 backdrop-blur-sm flex flex-col items-center justify-center gap-4">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-indigo-600 animate-pulse uppercase tracking-widest text-sm">রিকভারি মেইলসহ পাঠানো হচ্ছে...</p>
          </div>
        )}

        {/* Header Section */}
        <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-3">
          <span className="text-2xl">📋</span>
          <h2 className="text-xl font-black text-slate-900">নতুন কাজ বরাদ্দ করা হয়েছে</h2>
        </div>

        <div className="p-6 space-y-4">
          <div className="flex items-center gap-2 text-lg font-bold text-gray-800 mb-2">
            <span className="text-2xl">👇</span> নিচের তথ্য দিয়ে জিমেইল খুলুন:
          </div>

          <div className="space-y-1">
             <div className="flex items-center gap-2 p-4">
                <div className="text-blue-500"><User className="w-5 h-5" /></div>
                <div className="flex flex-col">
                   <p className="text-sm font-bold text-gray-800">First Name:- <span className="font-medium text-slate-600 ml-1">{task.firstName}</span></p>
                   <p className="text-sm font-bold text-gray-800">Last Name:- <span className="font-medium text-slate-600 ml-1">{task.lastName}</span></p>
                </div>
             </div>

            <FieldRow 
              label="Gmail" 
              value={task.gmail} 
              icon={<Mail className="w-5 h-5" />} 
              copyable 
              fieldId="gmail"
            />

            <FieldRow 
              label="Password" 
              value={task.password} 
              icon={<Key className="w-5 h-5" />} 
              copyable 
              fieldId="pass"
            />

            <FieldRow 
              label="Recovery Mail" 
              value={task.recovery} 
              icon={<ShieldAlert className="w-5 h-5" />} 
              fieldId="recovery"
              copyable
              subLabel="AUTO SEND"
            />
          </div>

          {/* Rules Section */}
          <div className="mt-6 p-5 bg-slate-50 rounded-2xl border border-slate-100">
            <div className="flex items-center gap-2 mb-3 text-amber-600 font-black">
              <span className="text-xl">⚠️</span> নিয়মাবলী:
            </div>
            <ul className="space-y-2 text-sm font-bold text-slate-600 leading-relaxed">
              <li className="flex gap-2"><span>১.</span> ১০ মিনিটের মধ্যে কাজ জমা দিতে হবে।</li>
              <li className="flex gap-2"><span>২.</span> রিকভারি ইমেইল সেট না করলে পেমেন্ট পাবেন না।</li>
              <li className="flex gap-2"><span>৩.</span> কাজ করতে না পারলে 'Cancel' বাটনে চাপুন।</li>
              <li className="flex gap-2 text-red-600"><span>৪.</span> রিকভারি ইমেইল অটোমেটিক সিস্টেমে চলে যাবে।</li>
            </ul>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="grid grid-cols-2 gap-2 p-4 bg-slate-100">
          <button 
            disabled={isSubmitting}
            onClick={handleCompleteClick}
            className="flex items-center justify-center gap-2 py-4 bg-green-500 text-white rounded-xl font-black text-sm hover:bg-green-600 transition-all active:scale-95 shadow-md disabled:opacity-50"
          >
            <CheckCircle className="w-5 h-5" />
            সম্পন্ন হয়েছে
          </button>
          <button 
            disabled={isSubmitting}
            onClick={onCancel}
            className="flex items-center justify-center gap-2 py-4 bg-red-500 text-white rounded-xl font-black text-sm hover:bg-red-600 transition-all active:scale-95 shadow-md disabled:opacity-50"
          >
            <X className="w-5 h-5" />
            বাতিল করুন
          </button>
        </div>
      </div>
      <p className="text-center text-[10px] text-slate-400 mt-4 font-bold uppercase tracking-widest">
        Assigned at {new Date(task.assignedAt).toLocaleTimeString()}
      </p>
    </div>
  );
};

