import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import SupportBot from './components/SupportBot.tsx';
import TelegramDashboard from './components/TelegramDashboard.tsx';
import TaskAssignment from './components/TaskAssignment.tsx';
import { AccountModal, ReferralModal, TutorialModal, PricesModal, PremiumModal } from './components/Modals.tsx';
import { Order, ViewState, Task } from './types.ts';
import { Star, Zap, CheckCircle, X, Ban, Lock } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('store');
  const [orders, setOrders] = useState<Order[]>([]);
  const [usedGmails, setUsedGmails] = useState<string[]>([]);
  const [isPremium, setIsPremium] = useState(false);

  const [showToast, setShowToast] = useState(false);
  const [toastType, setToastType] = useState<'success' | 'cancel'>('success');
  const [toastMessage, setToastMessage] = useState({ title: '', sub: '', detail: '' });

  // Task state
  const [activeTask, setActiveTask] = useState<Task | null>(null);

  // Chat integration state
  const [isChatVisible, setIsChatVisible] = useState(false);
  const [chatInitialMessage, setChatInitialMessage] = useState('');

  // Modal states
  const [isAccountOpen, setIsAccountOpen] = useState(false);
  const [isReferralOpen, setIsReferralOpen] = useState(false);
  const [isTutorialOpen, setIsTutorialOpen] = useState(false);
  const [isPricesOpen, setIsPricesOpen] = useState(false);
  const [isPremiumOpen, setIsPremiumOpen] = useState(false);

  const WHATSAPP_GROUP_URL = "https://chat.whatsapp.com/G07De5sgX8IKOldlP1NeGc?mode=gi_t";

  useEffect(() => {
    const savedOrders = localStorage.getItem('croma_orders');
    if (savedOrders) {
      setOrders(JSON.parse(savedOrders));
    }
    const savedGmails = localStorage.getItem('croma_used_gmails');
    if (savedGmails) {
      setUsedGmails(JSON.parse(savedGmails));
    }
    const savedPremium = localStorage.getItem('croma_is_premium');
    if (savedPremium) {
      setIsPremium(JSON.parse(savedPremium));
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('croma_orders', JSON.stringify(orders));
  }, [orders]);

  useEffect(() => {
    localStorage.setItem('croma_used_gmails', JSON.stringify(usedGmails));
  }, [usedGmails]);

  useEffect(() => {
    localStorage.setItem('croma_is_premium', JSON.stringify(isPremium));
  }, [isPremium]);

  const generateNewTask = () => {
    const firstNames = [
      'Cory', 'Ryan', 'Liam', 'Noah', 'James', 'Oliver', 'Lucas', 'Mason', 'Ethan', 'Logan',
      'Aiden', 'Emma', 'Olivia', 'Ava', 'Isabella', 'Sophia', 'Mia', 'Charlotte', 'Amelia', 'Harper',
      'Benjamin', 'Henry', 'Alexander', 'Sebastian', 'Jack', 'Samuel', 'Owen', 'Leo', 'Wyatt', 'Tierra'
    ];

    const lastNames = [
      'X', 'S.', 'M.', 'D.', 'Smith', 'Jones', 'Miller', 'Davis', 'Wilson', 'Moore',
      'Taylor', 'Anderson', 'Thomas', 'Jackson', 'White', 'Harris', 'Martin'
    ];

    const prefixes = [
      'jatogivov', 'nexilo', 'vunap', 'zider', 'polima', 'murex', 'kinop', 'tewab',
      'fomila', 'remux', 'lonap', 'zexar', 'vapilo', 'nerox', 'kubat'
    ];

    let gmail = '';
    let attempts = 0;

    while (attempts < 5000) {
      const prefix = prefixes[Math.floor(Math.random() * prefixes.length)];
      const randomNum = Math.floor(Math.random() * 9999999) + 1000;
      const candidate = `${prefix}${randomNum}@gmail.com`;

      if (!usedGmails.includes(candidate)) {
        gmail = candidate;
        break;
      }
      attempts++;
    }

    if (!gmail) gmail = `user${Date.now()}@gmail.com`;

    const firstName = firstNames[Math.floor(Math.random() * firstNames.length)];
    const lastName = lastNames[Math.floor(Math.random() * lastNames.length)];

    const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789!@#$%^&*";
    let pass = "";
    for (let i = 0; i < 16; i++) pass += chars.charAt(Math.floor(Math.random() * chars.length));

    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      firstName,
      lastName,
      gmail,
      password: pass,
      recovery: 'panelsajibyt@gmail.com', 
      assignedAt: Date.now()
    };

    setActiveTask(newTask);
    setIsChatVisible(false);
  };

  const handleTaskComplete = () => {
    if (!activeTask) return;

    const submissionText = `Gmail Submission:\n📧 Gmail: ${activeTask.gmail}\n🔑 Pass: ${activeTask.password}\n🛡️ Recovery: ${activeTask.recovery}`;

    navigator.clipboard.writeText(submissionText)
      .then(() => {
        window.open(WHATSAPP_GROUP_URL, '_blank');

        const newOrder: Order = {
          id: Math.random().toString(36).substr(2, 9),
          serviceId: 'gmail-sell',
          serviceName: 'Gmail Submission',
          quantity: 1,
          paymentMethod: 'Task System',
          customerName: 'Sellers Hub',
          customerHandle: '@seller',
          details: submissionText,
          status: 'pending',
          createdAt: Date.now(),
        };

        setUsedGmails(prev => [...prev, activeTask.gmail]);
        setOrders([newOrder, ...orders]);
        setActiveTask(null);
        setToastType('success');
        setToastMessage({ 
          title: 'সফলভাবে কপি করা হয়েছে!', 
          sub: 'তথ্য কপি হয়েছে। এখন হোয়াটসঅ্যাপ গ্রুপে গিয়ে পেস্ট করুন।',
          detail: 'অটোমেটিক গ্রুপে রিডাইরেক্ট করা হচ্ছে...'
        });
        setShowToast(true);
        setTimeout(() => setShowToast(false), 8000);
      })
      .catch(err => {
        console.error('Clipboard error:', err);
        window.open(WHATSAPP_GROUP_URL, '_blank');
        setActiveTask(null);
      });
  };

  const handleTaskCancel = () => {
    if (!activeTask) return;
    setActiveTask(null);
    setToastType('cancel');
    setToastMessage({ 
      title: 'কাজটি বাতিল করা হয়েছে!', 
      sub: `আপনি ${activeTask.gmail} এর কাজটি বাতিল করেছেন।`,
      detail: 'এটি এখন অন্য ইউজারদের জন্য উন্মুক্ত।'
    });
    setShowToast(true);
    setTimeout(() => setShowToast(false), 6000);
  };

  const handleUpdateStatus = (id: string, status: Order['status']) => {
    setOrders(orders.map(o => o.id === id ? { ...o, status } : o));
  };

  const handleDeleteOrder = (id: string) => {
    if (confirm('Delete this order record?')) {
      setOrders(orders.filter(o => o.id !== id));
    }
  };

  const openChatWithContext = (msg: string) => {
    setChatInitialMessage(msg);
    setIsChatVisible(true);
    setActiveTask(null);
    setTimeout(() => {
      document.getElementById('support-chat')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleUnlockPremium = () => {
    setIsPremium(true);
    setIsPremiumOpen(false);
    setToastType('success');
    setToastMessage({ 
      title: 'Premium Unlocked!', 
      sub: 'আপনি এখন সকল প্রিমিয়াম ফিচার ব্যবহার করতে পারবেন।',
      detail: 'Welcome to MAHABUB VIP Hub.'
    });
    setShowToast(true);
    setTimeout(() => setShowToast(false), 5000);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Navbar 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        orderCount={orders.filter(o => o.status === 'pending').length}
      />

      <main className="flex-1 pb-20">
        {currentView === 'store' && (
          <div className="animate-in fade-in slide-in-from-top-2 duration-500">
            {/* Hero Section */}
            <section className="relative overflow-hidden bg-[#0F172A] pt-24 pb-20 px-4">
              <div className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-hidden">
                <div className="absolute -top-24 -left-24 w-96 h-96 bg-indigo-600/20 blur-[100px] rounded-full"></div>
                <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-violet-600/20 blur-[100px] rounded-full"></div>
              </div>

              <div className="max-w-4xl mx-auto text-center relative z-10">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-indigo-400 text-xs font-bold uppercase tracking-widest mb-8">
                  <Star className={`w-3 h-3 ${isPremium ? 'fill-amber-400 text-amber-400' : 'fill-indigo-400'}`} />
                  {isPremium ? 'MAHABUB VIP MEMBER' : 'Official Trusted Hub BD'}
                </div>

                <h1 className="text-5xl md:text-7xl font-black text-white mb-8 tracking-tight">
                  MAHABUB <br />
                  <span className={`text-transparent bg-clip-text bg-gradient-to-r ${isPremium ? 'from-amber-400 via-orange-400 to-yellow-400' : 'from-indigo-400 via-sky-400 to-emerald-400'}`}>
                    {isPremium ? 'VIP Marketplace' : 'Trusted Marketplace'}
                  </span>
                </h1>

                <div className="mb-4">
                  <TelegramDashboard 
                    isPremium={isPremium}
                    onSell={generateNewTask}
                    onAccount={() => setIsAccountOpen(true)}
                    onReferral={() => setIsReferralOpen(true)}
                    onWithdraw={() => {
                      if (!isPremium) setIsPremiumOpen(true);
                      else openChatWithContext('আমি পেমেন্ট উইথড্র করতে চাই।');
                    }}
                    onSupport={() => window.open(WHATSAPP_GROUP_URL, '_blank')}
                    onPrices={() => setIsPricesOpen(true)}
                    onTutorial={() => setIsTutorialOpen(true)}
                    onPremium={() => setIsPremiumOpen(true)}
                  />
                </div>

                {activeTask && (
                  <TaskAssignment 
                    task={activeTask} 
                    onComplete={handleTaskComplete} 
                    onCancel={handleTaskCancel} 
                  />
                )}

                {!activeTask && (
                  <div id="support-chat">
                    <SupportBot 
                      isVisible={isChatVisible} 
                      onClose={() => setIsChatVisible(false)}
                      initialMessage={chatInitialMessage}
                    />
                  </div>
                )}
              </div>
            </section>
          </div>
        )}

        {currentView === 'admin' && (
          <div className="animate-in fade-in duration-500">
            <AdminDashboard 
              orders={orders} 
              onUpdateStatus={handleUpdateStatus} 
              onDeleteOrder={handleDeleteOrder} 
            />
          </div>
        )}
      </main>

      {isAccountOpen && <AccountModal onClose={() => setIsAccountOpen(false)} orders={orders} />}
      {isReferralOpen && <ReferralModal onClose={() => setIsReferralOpen(false)} />}
      {isTutorialOpen && <TutorialModal onClose={() => setIsTutorialOpen(false)} />}
      {isPricesOpen && <PricesModal onClose={() => setIsPricesOpen(false)} />}
      {isPremiumOpen && <PremiumModal onClose={() => setIsPremiumOpen(false)} onUnlock={handleUnlockPremium} />}

      {/* Enhanced Toast Notification */}
      {showToast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] animate-in slide-in-from-bottom-10 duration-500 w-full max-w-sm px-4">
          <div className="bg-slate-900 text-white px-6 py-5 rounded-3xl shadow-2xl flex items-center gap-4 border border-white/10">
            <div className={`${toastType === 'success' ? 'bg-emerald-500' : 'bg-red-500'} p-2 rounded-full shrink-0`}>
              {toastType === 'success' ? <CheckCircle className="w-5 h-5 text-white" /> : <Ban className="w-5 h-5 text-white" />}
            </div>
            <div className="flex-1 text-left">
              <p className="font-bold leading-none mb-1">{toastMessage.title}</p>
              <p className="text-xs text-slate-400 leading-tight">{toastMessage.sub}</p>
              <p className="text-[10px] text-indigo-400 font-black mt-1 uppercase tracking-widest">{toastMessage.detail}</p>
            </div>
            <button onClick={() => setShowToast(false)} className="ml-auto p-1 hover:bg-white/10 rounded-lg shrink-0">
              <X className="w-5 h-5 text-slate-500" />
            </button>
          </div>
        </div>
      )}

      <footer className="bg-slate-900 py-16 px-4 border-t border-white/5">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-12">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl">
              <Zap className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-black text-white tracking-tighter">MAHABUB</span>
          </div>
          <div className="flex gap-10 text-sm font-bold text-slate-400">
            <a href="#" className="hover:text-indigo-400 transition-colors">Safety</a>
            <a href="#" className="hover:text-indigo-400 transition-colors">Pricing</a>
            <a href="#" className="hover:text-indigo-400 transition-colors">API</a>
            <a href="#" className="hover:text-indigo-400 transition-colors" onClick={() => window.open(WHATSAPP_GROUP_URL, '_blank')}>Support</a>
          </div>
          <div className="text-center md:text-right">
            <p className="text-slate-400 text-sm font-medium">© 2024 Mahabub Digital Services.</p>
            <p className="text-slate-600 text-[10px] mt-1 font-bold uppercase tracking-widest">Built for Trusted Trading</p>
          </div>
        </div>
      </footer>
    </div>
  );
};

