              <button 
                onClick={() => setActiveTab('balance')}
                className={`px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'balance' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500'}`}
              >
                Add Money
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
            {activeTab === 'orders' ? (
              <>
                {orders.length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-center">
                    <div className="p-8 bg-slate-50 rounded-full mb-6">
                      <Clock className="w-16 h-16 text-slate-200" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-900">পেন্ডিং কোনো কাজ নেই</h3>
                  </div>
                ) : (
                  <div className="border border-slate-100 rounded-3xl overflow-hidden shadow-sm">
                    <table className="w-full text-left">
                      <thead className="bg-slate-50/50 border-b border-slate-100">
                        <tr>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Service</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Customer</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                          <th className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Action</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-50">
                        {orders.map((order) => (
                          <tr key={order.id} className="hover:bg-slate-50/30 transition-colors group">
                            <td className="px-6 py-5">
                              <div className="flex flex-col">
                                <span className="font-bold text-slate-900 text-sm">{order.serviceName}</span>
                                <span className="text-[10px] text-slate-400">{new Date(order.createdAt).toLocaleTimeString()}</span>
                              </div>
                            </td>
                            <td className="px-6 py-5">
                              <span className="text-sm font-bold text-slate-900">{order.customerName}</span>
                            </td>
                            <td className="px-6 py-5">
                              <select 
                                value={order.status}
                                onChange={(e) => onUpdateStatus(order.id, e.target.value as Order['status'])}
                                className={`text-[10px] font-black px-3 py-1.5 rounded-full border-none focus:ring-2 focus:ring-indigo-100 cursor-pointer uppercase tracking-widest ${
                                  order.status === 'pending' ? 'bg-amber-100 text-amber-700' : 
                                  order.status === 'completed' ? 'bg-green-100 text-green-700' : 
                                  'bg-rose-100 text-rose-700'
                                }`}
                              >
                                <option value="pending">Pending</option>
                                <option value="completed">Approved</option>
                                <option value="cancelled">Reject</option>
                              </select>
                            </td>
                            <td className="px-6 py-5 text-right">
                              <div className="flex items-center justify-end gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button 
                                  onClick={() => alert(`Details:\n${order.details}`)}
                                  className="p-2 text-slate-400 hover:text-indigo-600"
                                >
                                  <AlertCircle className="w-5 h-5" />
                                </button>
                                <button 
                                  onClick={() => onDeleteOrder(order.id)}
                                  className="p-2 text-slate-400 hover:text-rose-600"
                                >
                                  <Trash2 className="w-5 h-5" />
                                </button>
                              </div>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </>
            ) : (
              <div className="max-w-md mx-auto py-12 animate-in slide-in-from-bottom-4">
                <div className="text-center mb-10">
                  <div className="inline-flex items-center justify-center p-5 bg-emerald-100 text-emerald-600 rounded-full mb-6 relative">
                    <CircleDollarSign className="w-10 h-10" />
                    <Zap className="absolute -top-1 -right-1 w-6 h-6 text-emerald-500 fill-emerald-500 animate-bounce" />
                  </div>
                  <h3 className="text-2xl font-black text-slate-900">অটো টাকা অ্যাড</h3>
                  <p className="text-slate-500 font-medium">নিচে টাকার পরিমাণ দিয়ে 'Add' বাটনে ক্লিক করুন।</p>
                </div>

                <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">টাকার পরিমাণ (BDT)</label>
                    <input 
                      type="number"
                      value={balanceAmount}
                      onChange={(e) => setBalanceAmount(e.target.value)}
                      placeholder="Amount to add..."
                      className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-2xl text-xl font-black text-slate-900 focus:outline-none focus:border-emerald-500 transition-all shadow-inner"
                    />
                  </div>

                  <button 
                    onClick={handleAddBalance}
                    className="w-full flex items-center justify-center gap-3 py-5 bg-emerald-600 text-white rounded-2xl font-black text-xl hover:bg-emerald-500 active:scale-[0.98] transition-all shadow-xl shadow-emerald-200"
                  >
                    <span>টাকা যোগ করুন</span>
                    <Send className="w-5 h-5" />
                  </button>
                </div>

                <div className="mt-12 p-6 bg-slate-900 rounded-2xl border border-white/10 text-white">
                  <p className="text-xs font-black uppercase tracking-widest opacity-50 mb-2">Notice</p>
                  <p className="text-sm font-medium leading-relaxed opacity-90">
                    এখান থেকে টাকা যোগ করলে সেটি সরাসরি ইউজারের 'My Account' ব্যালেন্সে রিফ্লেক্ট হবে।
                  </p>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 border-t border-gray-100 bg-slate-50/50">
             <div className="flex items-center justify-between">
                <div className="flex flex-col">
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Mahabub Admin Command</p>
                   <p className="text-xs font-bold text-indigo-600">Secure Protocol v2.1</p>
                </div>
                <button 
                  onClick={onClose}
                  className="px-6 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-lg"
                >
                  Close Panel
                </button>
             </div>
          </div>
        </div>
      </div>
    </>
  );
}; export default AdminDashboard;
